--- src/providers/anthropic-adapter.ts (before)
+++ src/providers/anthropic-adapter.ts (after)
@@ -90,11 +90,13 @@ export class AnthropicAdapter implements LLMProvider {

       if (m.role === 'tool') {
         // Tool result message
+        const toolContent = typeof m.content === 'string' ? m.content : '';
+        if (!toolContent) continue;  // Skip empty tool results
+        
         anthropicMessages.push({
           role: 'user',
           content: [{
             type:        'tool_result',
             tool_use_id: m.tool_call_id || '',
-            content:     typeof m.content === 'string' ? m.content : '',
+            content:     toolContent,
           }],
         });
         continue;
@@ -104,6 +106,7 @@ export class AnthropicAdapter implements LLMProvider {
         const parts: any[] = m.content.map((part: ContentPart) => {
           if (part.type === 'text') return { type: 'text', text: part.text };
           if (part.type === 'image_url') {
             // Convert OpenAI-style image_url to Anthropic source format
             const url = part.image_url.url;
@@ -129,14 +132,17 @@ export class AnthropicAdapter implements LLMProvider {
           }
           return { type: 'text', text: '' };
         });
-        anthropicMessages.push({ role: m.role === 'assistant' ? 'assistant' : 'user', content: parts });
+        // Filter out parts with empty text
+        const filteredParts = parts.filter(p => p.type !== 'text' || (p.type === 'text' && p.text));
+        if (filteredParts.length === 0) continue;  // Skip if no content remains
+        anthropicMessages.push({ role: m.role === 'assistant' ? 'assistant' : 'user', content: filteredParts });
         continue;
       }

       // Plain text message
-      anthropicMessages.push({
+      const textContent = typeof m.content === 'string' ? m.content : '';
+      if (!textContent) continue;  // Skip empty messages
+      
+      anthropicMessages.push({
         role:    m.role === 'assistant' ? 'assistant' : 'user',
-        content: typeof m.content === 'string' ? m.content : '',
+        content: textContent,
       });

